-- Enhanced coloring module schemas: skin (20), hair (21)
-- Dermatology-grade skin parameters (Fitzpatrick, melanin, translucency, sebum)
-- Trichology-grade hair parameters (Walker typing, porosity, strand thickness, growth patterns)

-- skin: 20 parameters
UPDATE luv_chassis_modules SET parameter_schema = '[{"key": "base_tone", "label": "Base Tone", "type": "color", "tier": "basic", "default": "#F5D6C3"}, {"key": "undertone", "label": "Undertone", "type": "enum", "tier": "basic", "options": ["warm", "cool", "neutral", "olive", "peach", "golden"], "default": "warm"}, {"key": "fitzpatrick", "label": "Fitzpatrick Type", "type": "enum", "tier": "basic", "options": ["I", "II", "III", "IV", "V", "VI"], "default": "II", "description": "Dermatological skin classification \u2014 I (very fair, always burns) to VI (deeply pigmented, never burns)"}, {"key": "depth", "label": "Skin Depth", "type": "enum", "tier": "basic", "options": ["very-fair", "fair", "light", "light-medium", "medium", "medium-dark", "dark", "very-dark", "deep"], "default": "fair", "description": "Overall lightness/darkness independent of undertone"}, {"key": "texture", "label": "Surface Texture", "type": "enum", "tier": "intermediate", "options": ["porcelain", "smooth", "satin", "natural", "slightly-textured", "textured", "weathered"], "default": "smooth"}, {"key": "luminosity", "label": "Luminosity", "type": "enum", "tier": "intermediate", "options": ["matte", "natural", "satin", "dewy", "radiant", "glass"], "default": "dewy", "description": "How light interacts with the skin surface \u2014 matte absorbs, glass reflects"}, {"key": "pore_visibility", "label": "Pore Visibility", "type": "enum", "tier": "intermediate", "options": ["invisible", "fine", "visible", "pronounced"], "default": "fine", "description": "Apparent pore size, especially on nose and cheeks"}, {"key": "translucency", "label": "Translucency", "type": "enum", "tier": "intermediate", "options": ["opaque", "slight", "moderate", "high", "very-high"], "default": "moderate", "description": "How much subsurface color (blood, veins) shows through \u2014 high = ethereal quality"}, {"key": "freckles", "label": "Freckle Distribution", "type": "enum", "tier": "intermediate", "options": ["none", "nose-bridge-only", "light-scatter", "moderate", "heavy", "full-face", "body-wide"], "default": "none"}, {"key": "elasticity", "label": "Elasticity", "type": "enum", "tier": "intermediate", "options": ["taut", "firm", "supple", "soft", "relaxed"], "default": "supple", "description": "Skin firmness and bounce-back \u2014 correlates with age and hydration"}, {"key": "vein_visibility", "label": "Vein Visibility", "type": "enum", "tier": "advanced", "options": ["hidden", "subtle", "visible", "prominent"], "default": "subtle", "description": "How visible veins are at temples, wrists, chest, and inner arms"}, {"key": "surface_sheen_zones", "label": "Sheen Zones", "type": "text", "tier": "advanced", "description": "Which areas tend toward oily sheen vs matte (e.g. T-zone oily, cheeks matte)"}, {"key": "blush_zones", "label": "Natural Blush Zones", "type": "text", "tier": "advanced", "description": "Where color rises with warmth, exertion, or emotion (cheeks, ears, chest, etc.)"}, {"key": "sun_response", "label": "Sun Response", "type": "enum", "tier": "advanced", "options": ["burns-only", "burns-then-tans", "tans-gradually", "tans-easily", "tans-deeply", "no-change"], "default": "burns-then-tans", "description": "How skin responds to UV exposure over time"}, {"key": "scar_tendency", "label": "Scar Type", "type": "enum", "tier": "advanced", "options": ["flat-fading", "flat-persistent", "raised", "keloid", "atrophic", "none-noted"], "default": "flat-fading", "description": "How the skin tends to scar \u2014 affects how old injuries read"}, {"key": "body_markings", "label": "Body Markings", "type": "text", "tier": "advanced", "description": "Tattoos, birthmarks, scars, or other permanent skin features on the body"}, {"key": "mole_pattern", "label": "Mole Pattern", "type": "enum", "tier": "advanced", "options": ["none", "sparse", "scattered", "clustered", "beauty-marks"], "default": "sparse"}, {"key": "melanin_distribution", "label": "Melanin Distribution", "type": "enum", "tier": "clinical", "options": ["even", "slight-variation", "moderate-variation", "high-variation", "hyperpigmented-zones", "hypopigmented-zones"], "default": "even", "description": "Uniformity of pigmentation across the body"}, {"key": "erythema_tendency", "label": "Erythema Tendency", "type": "enum", "tier": "clinical", "options": ["none", "mild", "moderate", "rosacea-prone", "high"], "default": "mild", "description": "Baseline tendency toward redness, especially in the face"}, {"key": "sebum_production", "label": "Sebum Production", "type": "enum", "tier": "clinical", "options": ["very-dry", "dry", "balanced", "oily", "very-oily", "combination"], "default": "balanced", "description": "Oil production level \u2014 affects surface appearance, especially in photography"}]'::jsonb WHERE slug = 'skin';

-- hair: 21 parameters
UPDATE luv_chassis_modules SET parameter_schema = '[{"key": "color", "label": "Primary Color", "type": "color", "tier": "basic", "default": "#2C1810"}, {"key": "natural_color", "label": "Natural Color", "type": "enum", "tier": "basic", "options": ["black", "dark-brown", "medium-brown", "light-brown", "dark-blonde", "medium-blonde", "light-blonde", "strawberry-blonde", "auburn", "red", "copper", "gray", "white", "silver"], "default": "dark-brown", "description": "Natural hair color before any processing or dyeing"}, {"key": "length", "label": "Length", "type": "enum", "tier": "basic", "options": ["buzzed", "pixie", "ear-length", "chin-length", "shoulder", "mid-back", "waist", "hip", "floor"], "default": "mid-back"}, {"key": "texture", "label": "Texture", "type": "enum", "tier": "basic", "options": ["1-straight", "2a-wavy", "2b-wavy", "2c-wavy", "3a-curly", "3b-curly", "3c-curly", "4a-coily", "4b-coily", "4c-coily"], "default": "2a-wavy", "description": "Andre Walker hair typing system \u2014 1 (straight) through 4c (tight coil)"}, {"key": "secondary_color", "label": "Secondary Color", "type": "color", "tier": "intermediate", "description": "Highlights, lowlights, ombre, or streaks"}, {"key": "color_pattern", "label": "Color Pattern", "type": "enum", "tier": "intermediate", "options": ["solid", "natural-variation", "highlights", "lowlights", "balayage", "ombre", "dip-dye", "roots-showing", "streaks", "two-tone"], "default": "natural-variation", "description": "How color is distributed through the hair"}, {"key": "volume", "label": "Volume", "type": "enum", "tier": "intermediate", "options": ["flat", "fine", "normal", "full", "voluminous", "very-full", "massive"], "default": "voluminous"}, {"key": "density", "label": "Density", "type": "enum", "tier": "intermediate", "options": ["thin", "fine", "medium", "thick", "very-thick"], "default": "medium", "description": "How many individual strands per square inch \u2014 distinct from volume"}, {"key": "strand_thickness", "label": "Strand Thickness", "type": "enum", "tier": "intermediate", "options": ["fine", "medium", "coarse", "very-coarse"], "default": "medium", "description": "Diameter of individual strands \u2014 affects how hair catches light"}, {"key": "style", "label": "Default Style", "type": "text", "tier": "intermediate", "description": "Default hairstyle (e.g. loose waves, high ponytail, box braids, curtain bangs)"}, {"key": "shine", "label": "Shine", "type": "enum", "tier": "advanced", "options": ["matte", "low-sheen", "natural", "glossy", "high-gloss", "mirror"], "default": "glossy"}, {"key": "movement", "label": "Movement", "type": "enum", "tier": "advanced", "options": ["stiff", "structured", "some-movement", "flowing", "bouncy", "wild", "gravity-defying"], "default": "flowing", "description": "How the hair moves and responds to motion and wind"}, {"key": "frizz", "label": "Frizz Level", "type": "enum", "tier": "advanced", "options": ["none", "minimal", "some", "moderate", "significant", "halo"], "default": "minimal"}, {"key": "parting", "label": "Part", "type": "enum", "tier": "advanced", "options": ["center", "left", "right", "deep-side", "zigzag", "no-part"], "default": "center"}, {"key": "bangs", "label": "Bangs/Fringe", "type": "enum", "tier": "advanced", "options": ["none", "curtain", "side-swept", "blunt", "wispy", "micro", "bottleneck", "choppy"], "default": "none"}, {"key": "hairline_shape", "label": "Hairline Shape", "type": "enum", "tier": "advanced", "options": ["straight", "rounded", "M-shaped", "widows-peak", "uneven", "high", "low"], "default": "rounded", "description": "Shape of the anterior hairline"}, {"key": "hair_health", "label": "Hair Health", "type": "enum", "tier": "advanced", "options": ["pristine", "healthy", "good", "some-damage", "damaged", "heat-damaged", "chemically-processed"], "default": "healthy", "description": "Overall condition \u2014 affects texture, split ends, shine consistency"}, {"key": "accessories", "label": "Hair Accessories", "type": "text", "tier": "advanced", "description": "Default hair accessories (clips, ribbons, pins, headbands, etc.)"}, {"key": "hair_weight", "label": "Hair Weight", "type": "enum", "tier": "clinical", "options": ["weightless", "light", "medium", "heavy", "very-heavy"], "default": "medium", "description": "How gravity affects the hair \u2014 heavier hair pulls straighter, falls more uniformly"}, {"key": "growth_pattern", "label": "Growth Pattern", "type": "enum", "tier": "clinical", "options": ["uniform", "cowlick", "double-crown", "whorl", "directional"], "default": "uniform", "description": "Natural growth direction quirks that affect styling"}, {"key": "porosity", "label": "Porosity", "type": "enum", "tier": "clinical", "options": ["low", "medium", "high"], "default": "medium", "description": "How readily hair absorbs and retains moisture \u2014 affects how it responds to humidity and products"}]'::jsonb WHERE slug = 'hair';
